  input [15:0] b,
  output eq,
  output lt,
  output gt
);
  assign eq = (a == b);
  assign lt = (a < b);
  assign gt = (a > b);
endmodule

module compare_wrapper();
  comparator_16bit cmp(.a(val_a), .b(val_b), .eq(equal), .lt(less_than), .gt(greater_than), .extra_signal(signal));
endmodule

after_code:
module comparator_16bit(
  input [15:0] a,
  input [15:0] b,
  output eq,
  output lt,
  output gt
);
  assign eq = (a == b);
  assign lt = (a < b);
  assign gt = (a > b);
endmodule

module compare_wrapper();
  comparator_16bit cmp(.a(val_a), .b(val_b), .eq(equal), .lt(less_than), .gt(greater_than));
